"use client";

import type { ComponentProps, FC } from "react";
import { useCallback, useEffect, useMemo, useState } from "react";
import { ChevronDownOutline, GlobeOutline } from "react-ionicons";

import type { Country } from "@/shared/types/country.types";

import { useCountries } from "@/shared/api/query-hooks/use-countries";
import { cn } from "../../lib/ui/cn";
import { getFlagEmoji } from "../../lib/utils/get-flag-emoji";

interface PhoneInputProps
  extends Omit<ComponentProps<"input">, "type" | "value" | "onChange"> {
  value?: string;
  onChange?: (value: string) => void;
  defaultCountryAlpha2?: string;
}

export const PhoneInput: FC<PhoneInputProps> = ({
  className,
  placeholder = "Eg. 501234567",
  value = "",
  onChange,
  defaultCountryAlpha2 = "UA",
  ...inputProps
}) => {
  const [localValue, setLocalValue] = useState("");
  const [isOpen, setIsOpen] = useState(false);
  const [selectedCountry, setSelectedCountry] = useState<Country | null>(null);
  const { data: countries = [], isLoading: countriesLoading } = useCountries();

  const enabledCountries = useMemo(
    () => countries.filter((c) => c.enabled),
    [countries],
  );

  useEffect(() => {
    if (enabledCountries.length > 0 && !selectedCountry) {
      const defaultCountry =
        enabledCountries.find((c) => c.alpha2 === defaultCountryAlpha2) ||
        enabledCountries[0];
      setSelectedCountry(defaultCountry);
    }
  }, [enabledCountries, selectedCountry, defaultCountryAlpha2]);

  useEffect(() => {
    if (!selectedCountry) return;

    const countryCode = selectedCountry.callingCodes[0] || "";

    if (value?.startsWith(countryCode)) {
      setLocalValue(value.slice(countryCode.length));
    } else {
      setLocalValue(value);
    }
  }, [value, selectedCountry]);

  const handleInputChange = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>) => {
      if (!selectedCountry) return;

      const inputValue = e.target.value;
      setLocalValue(inputValue);

      const countryCode = selectedCountry.callingCodes[0] || "";
      const fullPhoneNumber = inputValue ? `${countryCode}${inputValue}` : "";
      onChange?.(fullPhoneNumber);
    },
    [selectedCountry, onChange],
  );

  const handleCountrySelect = useCallback(
    (country: Country) => {
      setSelectedCountry(country);
      setIsOpen(false);

      const countryCode = country.callingCodes[0] || "";
      const fullPhoneNumber = localValue ? `${countryCode}${localValue}` : "";
      onChange?.(fullPhoneNumber);
    },
    [localValue, onChange],
  );

  if (countriesLoading) {
    return (
      <div
        className={cn(
          "flex h-10 w-full items-center gap-gap-default rounded-input border border-input bg-transparent px-input-200",
          className,
        )}
      >
        <span className="font-sans text-muted-foreground text-xs">
          Loading countries...
        </span>
      </div>
    );
  }

  const flagEmoji = getFlagEmoji(selectedCountry?.alpha2 || "");
  const countryCode = selectedCountry?.callingCodes[0] || "";

  return (
    <div className="relative w-full">
      <div
        className={cn(
          "flex h-10 w-full items-center gap-gap-default rounded-input border border-input bg-transparent px-input-200 transition-colors focus-within:ring-1 focus-within:ring-ring",
          className,
        )}
      >
        <button
          type="button"
          onClick={() => setIsOpen(!isOpen)}
          className="flex shrink-0 items-center gap-1.5 transition-opacity hover:opacity-70"
          disabled={!selectedCountry}
        >
          <span className="text-lg leading-none">
            {selectedCountry ? (
              flagEmoji
            ) : (
              <GlobeOutline width="20px" height="20px" />
            )}
          </span>
          <span className="font-sans font-semibold text-foreground text-xs">
            {countryCode}
          </span>
          <ChevronDownOutline
            width="16px"
            height="16px"
            className={cn(
              "text-foreground transition-transform",
              isOpen && "rotate-180",
            )}
          />
        </button>

        <div className="h-[2.0625rem] w-px bg-border/25" />

        <input
          type="tel"
          placeholder={placeholder}
          value={localValue}
          onChange={handleInputChange}
          className="!border-0 focus:!border-0 !outline-none focus:!outline-none !ring-0 focus:!ring-0 flex-1 bg-transparent p-[0px] font-sans font-semibold text-foreground text-xs leading-[1.2em] placeholder:text-muted-foreground disabled:cursor-not-allowed disabled:opacity-50"
          {...inputProps}
          disabled={!selectedCountry || inputProps.disabled}
        />
      </div>

      {isOpen && (
        <>
          <button
            type="button"
            className="fixed inset-0 z-10 cursor-default"
            onClick={() => setIsOpen(false)}
            onKeyDown={(e) => {
              if (e.key === "Escape") {
                setIsOpen(false);
              }
            }}
            aria-label="Close country selector"
            tabIndex={-1}
          />
          <div className="absolute top-full z-20 mt-1 max-h-60 w-full overflow-y-auto rounded-input border border-input bg-background shadow-lg">
            {enabledCountries.map((country) => {
              const flag = getFlagEmoji(country.alpha2);
              const code = country.callingCodes[0] || "";

              return (
                <button
                  key={country.id}
                  type="button"
                  onClick={() => handleCountrySelect(country)}
                  className={cn(
                    "flex w-full items-center gap-2 px-3 py-2 text-left transition-colors hover:bg-secondary/50",
                    selectedCountry?.id === country.id && "bg-secondary",
                  )}
                >
                  <span className="text-lg leading-none">{flag}</span>
                  <span className="flex-1 font-sans text-foreground text-sm">
                    {country.name}
                  </span>
                  <span className="font-sans font-semibold text-foreground text-xs">
                    {code}
                  </span>
                </button>
              );
            })}
          </div>
        </>
      )}
    </div>
  );
};

