const SOCIAL_BUTTONS = [
  { key: "google", Icon: GoogleIcon, label: "Google" },
  { key: "apple", Icon: AppleIcon, label: "Apple" },
  { key: "uaepass", Icon: UaePassIcon, label: "UAE Pass" },
];

export function SignupForm() {
  const router = useRouter();

  const checkEmailExists = useCheckEmailExists();
  const checkPhoneExists = useCheckPhoneExists();

  const form = useForm<SignupFormData>({
    resolver: zodResolver(signupSchema),
    defaultValues: {
      firstName: "",
      lastName: "",
      email: "",
      phone: "",
      uaeResident: false,
    },
  });

  const { isSubmitting } = form.formState;

  const onSubmit = async (data: SignupFormData) => {
    try {
      const [emailCheckResult, phoneCheckResult] = await Promise.all([
        checkEmailExists.mutateAsync(data.email),
        checkPhoneExists.mutateAsync(data.phone),
      ]);

      let hasErrors = false;

      if (emailCheckResult.exists) {
        form.setError("email", {
          type: "manual",
          message:
            "This email is already registered. Please use a different email or sign in.",
        });
        hasErrors = true;
      }

      if (phoneCheckResult.exists) {
        form.setError("phone", {
          type: "manual",
          message:
            "This phone number is already registered. Please use a different number or sign in.",
        });
        hasErrors = true;
      }

      if (hasErrors) {
        return;
      }

      const otpResponse = await sendOtp({
        email: data.email,
        phone: data.phone,
        type: OtpType.SIGN_UP,
      });

      authStorage.signup.set({
        email: data.email,
        phone: data.phone,
        firstName: data.firstName,
        lastName: data.lastName,
        role: USER_ROLES.SELLER,
        referralCode: undefined,
        devEmailOtp: otpResponse.otp,
        devPhoneOtp: otpResponse.otp,
      });

      if (otpResponse.otp) {
        toast.success("OTP Generated", {
          description: "Check the verification page for your OTP codes",
        });
      } else {
        toast.success("OTP Sent", {
          description: "Please check your email and phone for OTP codes",
        });
      }

      router.push(APP_ROUTES.AUTH.VERIFY_OTP);
    } catch {
      toast.error("Failed to Send OTP", {
        description: "Please try again later",
      });
    }
  };

  return (
    <div className="flex w-full flex-col gap-8">
      {/* Header */}
      <div className="flex flex-col gap-2">
        <h1 className="font-light font-new-serif text-2xl text-[#44403C] leading-[120%]">
          Join LuxFlow
        </h1>
        <p className="font-new-sans text-[#44403C] text-base leading-[150%] tracking-[-0.01em]">
          Get valuations, manage your offers, and unlock liquidity for your
          luxury items.
        </p>
      </div>

      {/* Social Buttons */}
      <div className="flex gap-2">
        {SOCIAL_BUTTONS.map(({ key, Icon, label }) => (
          <button
            key={key}
            type="button"
            disabled
            className="flex flex-1 cursor-not-allowed items-center justify-center gap-2 rounded-[4px] border border-[#A8A29E] bg-[#F5F3EF] px-4 py-3 font-medium font-new-sans text-[#44403C] text-sm tracking-[-0.01em] opacity-70"
          >
            <Icon />
            <span>{label}</span>
          </button>
        ))}
      </div>

      {/* Form Section */}
      <div className="flex flex-col gap-5">
        {/* OR Divider */}
        <div className="flex items-center gap-4">
          <div className="flex-1 border-[#D6D3D1] border-t" />
          <span className="font-bold font-new-sans text-[#A8A29E] text-sm tracking-[-0.01em]">
            OR
          </span>
          <div className="flex-1 border-[#D6D3D1] border-t" />
        </div>

        <Form {...form}>
          <form
            onSubmit={form.handleSubmit(onSubmit)}
            className="flex flex-col gap-5"
          >
            <div className="flex flex-col gap-2">
              {/* First Name + Last Name */}
              <div className="grid grid-cols-2 gap-2">
                <FormField
                  control={form.control}
                  name="firstName"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel className="font-new-sans font-normal text-[#44403C] text-sm leading-[130%]">
                        First Name
                      </FormLabel>
                      <FormControl>
                        <Input
                          placeholder="Enter your first name"
                          className="h-12 rounded-[4px] border-[#A8A29E] bg-[#F5F3EF] px-3 font-new-sans text-[#44403C] text-sm placeholder:text-[#A8A29E]"
                          {...field}
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />
                <FormField
                  control={form.control}
                  name="lastName"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel className="font-new-sans font-normal text-[#44403C] text-sm leading-[130%]">
                        Last Name
                      </FormLabel>
                      <FormControl>
                        <Input
                          placeholder="Enter your last name"
                          className="h-12 rounded-[4px] border-[#A8A29E] bg-[#F5F3EF] px-3 font-new-sans text-[#44403C] text-sm placeholder:text-[#A8A29E]"
                          {...field}
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />
              </div>

              {/* Phone Number */}
              <FormField
                control={form.control}
                name="phone"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel className="font-new-sans font-normal text-[#44403C] text-sm leading-[130%]">
                      Phone Number
                    </FormLabel>
                    <FormControl>
                      <PhoneInput
                        defaultCountryAlpha2="AE"
                        placeholder="e.g. 50-123-4567"
                        {...field}
                      />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />

              {/* Email */}
              <FormField
                control={form.control}
                name="email"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel className="font-new-sans font-normal text-[#44403C] text-sm leading-[130%]">
                      Email
                    </FormLabel>
                    <FormControl>
                      <Input
                        placeholder="Enter your email"
                        type="email"
                        className="h-12 rounded-[4px] border-[#A8A29E] bg-[#F5F3EF] px-3 font-new-sans text-[#44403C] text-sm placeholder:text-[#A8A29E]"
                        {...field}
                      />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />

              {/* UAE Residency Checkbox */}
              <FormField
                control={form.control}
                name="uaeResident"
                render={({ field }) => (
                  <FormItem>
                    <div className="flex items-center gap-2">
                      <Checkbox
                        id="uaeResident"
                        checked={field.value}
                        onCheckedChange={field.onChange}
                        className="data-[state=checked]:border-[#021171] data-[state=checked]:bg-[#021171]"
                      />
                      <FormLabel
                        htmlFor="uaeResident"
                        className="cursor-pointer font-new-sans font-normal text-[#44403C] text-sm leading-[150%] tracking-[-0.01em]"
                      >
                        I confirm I reside, or have an address in UAE
                      </FormLabel>
                    </div>
                    <FormMessage />
                  </FormItem>
                )}
              />
            </div>

            {/* OTP Notice */}
            <p className="font-new-sans text-[#44403C] text-sm leading-[150%] tracking-[-0.01em]">
              You will receive a <strong>one-time code</strong> to your email
              and phone to verify your profile.
            </p>

            {/* Continue Button */}
            <Button
              type="submit"
              disabled={isSubmitting}
              className="flex h-12 w-full items-center justify-center rounded-[4px] bg-[#021171] font-medium font-new-sans text-[#F5F3EF] text-base transition-opacity hover:opacity-90 disabled:cursor-not-allowed disabled:opacity-70"
            >
              {isSubmitting ? "Sending..." : "Continue"}
            </Button>

            {/* Login link */}
            <p className="text-center font-new-sans text-[#44403C] text-sm leading-[150%] tracking-[-0.01em]">
              Already have an account?{" "}
              <Link
                href={APP_ROUTES.AUTH.SIGN_IN}
                className="font-semibold text-[#44403C] hover:opacity-70"
              >
                Login
              </Link>
            </p>
          </form>
        </Form>
      </div>
    </div>
  );
}

"use client";

import type { ComponentProps, FC } from "react";
import { useCallback, useEffect, useMemo, useState } from "react";
import { ChevronDownOutline, GlobeOutline } from "react-ionicons";

import type { Country } from "@/shared/types/country.types";

import { useCountries } from "@/shared/api/query-hooks/use-countries";
import { cn } from "../../lib/ui/cn";
import { getFlagEmoji } from "../../lib/utils/get-flag-emoji";

interface PhoneInputProps
  extends Omit<ComponentProps<"input">, "type" | "value" | "onChange"> {
  value?: string;
  onChange?: (value: string) => void;
  defaultCountryAlpha2?: string;
}

export const PhoneInput: FC<PhoneInputProps> = ({
  className,
  placeholder = "Eg. 501234567",
  value = "",
  onChange,
  defaultCountryAlpha2 = "UA",
  ...inputProps
}) => {
  const [localValue, setLocalValue] = useState("");
  const [isOpen, setIsOpen] = useState(false);
  const [selectedCountry, setSelectedCountry] = useState<Country | null>(null);
  const { data: countries = [], isLoading: countriesLoading } = useCountries();

  const enabledCountries = useMemo(
    () => countries.filter((c) => c.enabled),
    [countries],
  );

  useEffect(() => {
    if (enabledCountries.length > 0 && !selectedCountry) {
      const defaultCountry =
        enabledCountries.find((c) => c.alpha2 === defaultCountryAlpha2) ||
        enabledCountries[0];
      setSelectedCountry(defaultCountry);
    }
  }, [enabledCountries, selectedCountry, defaultCountryAlpha2]);

  useEffect(() => {
    if (!selectedCountry) return;

    const countryCode = selectedCountry.callingCodes[0] || "";

    if (value?.startsWith(countryCode)) {
      setLocalValue(value.slice(countryCode.length));
    } else {
      setLocalValue(value);
    }
  }, [value, selectedCountry]);

  const handleInputChange = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>) => {
      if (!selectedCountry) return;

      const inputValue = e.target.value;
      setLocalValue(inputValue);

      const countryCode = selectedCountry.callingCodes[0] || "";
      const fullPhoneNumber = inputValue ? `${countryCode}${inputValue}` : "";
      onChange?.(fullPhoneNumber);
    },
    [selectedCountry, onChange],
  );

  const handleCountrySelect = useCallback(
    (country: Country) => {
      setSelectedCountry(country);
      setIsOpen(false);

      const countryCode = country.callingCodes[0] || "";
      const fullPhoneNumber = localValue ? `${countryCode}${localValue}` : "";
      onChange?.(fullPhoneNumber);
    },
    [localValue, onChange],
  );

  if (countriesLoading) {
    return (
      <div
        className={cn(
          "flex h-10 w-full items-center gap-gap-default rounded-input border border-input bg-transparent px-input-200",
          className,
        )}
      >
        <span className="font-sans text-muted-foreground text-xs">
          Loading countries...
        </span>
      </div>
    );
  }

  const flagEmoji = getFlagEmoji(selectedCountry?.alpha2 || "");
  const countryCode = selectedCountry?.callingCodes[0] || "";

  return (
    <div className="relative w-full">
      <div
        className={cn(
          "flex h-10 w-full items-center gap-gap-default rounded-input border border-input bg-transparent px-input-200 transition-colors focus-within:ring-1 focus-within:ring-ring",
          className,
        )}
      >
        <button
          type="button"
          onClick={() => setIsOpen(!isOpen)}
          className="flex shrink-0 items-center gap-1.5 transition-opacity hover:opacity-70"
          disabled={!selectedCountry}
        >
          <span className="text-lg leading-none">
            {selectedCountry ? (
              flagEmoji
            ) : (
              <GlobeOutline width="20px" height="20px" />
            )}
          </span>
          <span className="font-sans font-semibold text-foreground text-xs">
            {countryCode}
          </span>
          <ChevronDownOutline
            width="16px"
            height="16px"
            className={cn(
              "text-foreground transition-transform",
              isOpen && "rotate-180",
            )}
          />
        </button>

        <div className="h-[2.0625rem] w-px bg-border/25" />

        <input
          type="tel"
          placeholder={placeholder}
          value={localValue}
          onChange={handleInputChange}
          className="!border-0 focus:!border-0 !outline-none focus:!outline-none !ring-0 focus:!ring-0 flex-1 bg-transparent p-[0px] font-sans font-semibold text-foreground text-xs leading-[1.2em] placeholder:text-muted-foreground disabled:cursor-not-allowed disabled:opacity-50"
          {...inputProps}
          disabled={!selectedCountry || inputProps.disabled}
        />
      </div>

      {isOpen && (
        <>
          <button
            type="button"
            className="fixed inset-0 z-10 cursor-default"
            onClick={() => setIsOpen(false)}
            onKeyDown={(e) => {
              if (e.key === "Escape") {
                setIsOpen(false);
              }
            }}
            aria-label="Close country selector"
            tabIndex={-1}
          />
          <div className="absolute top-full z-20 mt-1 max-h-60 w-full overflow-y-auto rounded-input border border-input bg-background shadow-lg">
            {enabledCountries.map((country) => {
              const flag = getFlagEmoji(country.alpha2);
              const code = country.callingCodes[0] || "";

              return (
                <button
                  key={country.id}
                  type="button"
                  onClick={() => handleCountrySelect(country)}
                  className={cn(
                    "flex w-full items-center gap-2 px-3 py-2 text-left transition-colors hover:bg-secondary/50",
                    selectedCountry?.id === country.id && "bg-secondary",
                  )}
                >
                  <span className="text-lg leading-none">{flag}</span>
                  <span className="flex-1 font-sans text-foreground text-sm">
                    {country.name}
                  </span>
                  <span className="font-sans font-semibold text-foreground text-xs">
                    {code}
                  </span>
                </button>
              );
            })}
          </div>
        </>
      )}
    </div>
  );
};

