import { ApiKeys } from "@/shared/api/query-keys";
import { getCountries } from "@/shared/api/services/countries";
import { getQueryClientServer } from "@/shared/lib/api/get-query-client-server";
import { SignupForm } from "@/widgets/signup-form";

export default async function SignupPage() {
  const queryClient = getQueryClientServer();

  await queryClient.prefetchQuery({
    queryKey: ApiKeys.countries(),
    queryFn: getCountries,
    staleTime: 60 * 60 * 24,
  });

  return (
    <HydrationBoundary state={dehydrate(queryClient)}>
      <SignupForm />
    </HydrationBoundary>
  );
}

